# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import os
import time
from datetime import datetime

app = Flask(__name__)

ES_HOST = os.getenv('ELASTICSEARCH_HOST', 'localhost:9200')
ES_INDEX = os.getenv('ELASTICSEARCH_INDEX', 'products')
ES_USERNAME = os.getenv('ELASTICSEARCH_USERNAME', '')
ES_PASSWORD = os.getenv('ELASTICSEARCH_PASSWORD', '')

if ES_USERNAME and ES_PASSWORD:
    es = Elasticsearch(
        [ES_HOST],
        http_auth=(ES_USERNAME, ES_PASSWORD),
        timeout=30,
        max_retries=3,
        retry_on_timeout=True
    )
else:
    es = Elasticsearch(
        [ES_HOST],
        timeout=30,
        max_retries=3,
        retry_on_timeout=True
    )


def cache_response(timeout=300):
    def decorator(f):
        cache = {}
        cache_times = {}
        
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = request.full_path
            current_time = time.time()
            
            if cache_key in cache and cache_key in cache_times:
                if current_time - cache_times[cache_key] < timeout:
                    return cache[cache_key]
            
            result = f(*args, **kwargs)
            cache[cache_key] = result
            cache_times[cache_key] = current_time
            
            if len(cache) > 1000:
                oldest_key = min(cache_times, key=cache_times.get)
                del cache[oldest_key]
                del cache_times[oldest_key]
            
            return result
        
        return decorated_function
    return decorator


@app.route('/api/search', methods=['GET'])
@cache_response(timeout=300)
def search_products():
    try:
        query = request.args.get('q', '').strip()
        
        if not query:
            return jsonify({
                'success': False,
                'error': 'Search query parameter "q" is required',
                'results': [],
                'total': 0
            }), 400
        
        page = request.args.get('page', 1, type=int)
        page_size = request.args.get('page_size', 20, type=int)
        
        page = max(1, page)
        page_size = min(max(1, page_size), 100)
        
        from_index = (page - 1) * page_size
        
        search_body = {
            'query': {
                'bool': {
                    'should': [
                        {
                            'multi_match': {
                                'query': query,
                                'fields': ['name^3', 'description^2', 'category', 'brand', 'tags'],
                                'type': 'best_fields',
                                'fuzziness': 'AUTO',
                                'operator': 'or'
                            }
                        },
                        {
                            'match_phrase': {
                                'name': {
                                    'query': query,
                                    'boost': 5
                                }
                            }
                        },
                        {
                            'match_phrase_prefix': {
                                'name': {
                                    'query': query,
                                    'boost': 2
                                }
                            }
                        }
                    ],
                    'minimum_should_match': 1
                }
            },
            'from': from_index,
            'size': page_size,
            'sort': [
                '_score',
                {'created_at': {'order': 'desc'}}
            ],
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<mark>'],
                'post_tags': ['</mark>']
            }
        }
        
        category = request.args.get('category')
        if category:
            search_body['query']['bool']['filter'] = [
                {'term': {'category.keyword': category}}
            ]
        
        min_price = request.args.get('min_price', type=float)
        max_price = request.args.get('max_price', type=float)
        
        if min_price is not None or max_price is not None:
            price_filter = {'range': {'price': {}}}
            if min_price is not None:
                price_filter['range']['price']['gte'] = min_price
            if max_price is not None:
                price_filter['range']['price']['lte'] = max_price
            
            if 'filter' not in search_body['query']['bool']:
                search_body['query']['bool']['filter'] = []
            search_body['query']['bool']['filter'].append(price_filter)
        
        in_stock = request.args.get('in_stock')
        if in_stock and in_stock.lower() == 'true':
            if 'filter' not in search_body['query']['bool']:
                search_body['query']['bool']['filter'] = []
            search_body['query']['bool']['filter'].append({'term': {'in_stock': True}})
        
        response = es.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=30
        )
        
        results = []
        for hit in response['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            results.append(product)
        
        total = response['hits']['total']['value'] if isinstance(response['hits']['total'], dict) else response['hits']['total']
        
        total_pages = (total + page_size - 1) // page_size
        
        return jsonify({
            'success': True,
            'query': query,
            'results': results,
            'total': total,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_more': page < total_pages,
            'took_ms': response['took']
        }), 200
        
    except Exception as e:
        app.logger.error(f'Search error: {str(e)}')
        return jsonify({
            'success': False,
            'error': 'An error occurred while searching',
            'results': [],
            'total': 0
        }), 500


@app.route('/api/search/suggestions', methods=['GET'])
@cache_response(timeout=600)
def search_suggestions():
    try:
        query = request.args.get('q', '').strip()
        
        if not query or len(query) < 2:
            return jsonify({
                'success': True,
                'suggestions': []
            }), 200
        
        search_body = {
            'suggest': {
                'product-suggest': {
                    'prefix': query,
                    'completion': {
                        'field': 'name_suggest',
                        'size': 10,
                        'skip_duplicates': True,
                        'fuzzy': {
                            'fuzziness': 'AUTO'
                        }
                    }
                }
            }
        }
        
        response = es.search(
            index=ES_INDEX,
            body=search_body
        )
        
        suggestions = []
        if 'suggest' in response and 'product-suggest' in response['suggest']:
            for option in response['suggest']['product-suggest'][0]['options']:
                suggestions.append({
                    'text': option['text'],
                    'score': option['_score']
                })
        
        return jsonify({
            'success': True,
            'suggestions': suggestions
        }), 200
        
    except Exception as e:
        app.logger.error(f'Suggestions error: {str(e)}')
        return jsonify({
            'success': False,
            'error': 'An error occurred while fetching suggestions',
            'suggestions': []
        }), 500


@app.route('/health', methods=['GET'])
def health_check():
    try:
        es.cluster.health()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected',
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 503


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)